var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"TANK_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>통합 화력지원 시스템, 기동.</color>","JPN":"<color=#ffd34c>統合火力支援システム、起動。</color>","ENG":"<color=#ffd34c>Activating the Integrated Fire Support System.</color>","TWN":"<color=#ffd34c>統合火力支援系統，啟動。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TANK_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L5_1","type":"dialog","speaker":"TANK_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>전 기체 동기화 완료. 목표물 포착.</color>","JPN":"<color=#ffd34c>全機体同期完了。目標捕捉。</color>","ENG":"<color=#ffd34c>Synchronization complete. Target acquired.</color>","TWN":"<color=#ffd34c>全部機體同步完成，鎖定目標。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TANK_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"좋아, 포격 개시!","JPN":"よし、砲撃開始！","ENG":"Great. Fire!","TWN":"來吧，開始砲擊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"보고드립니다, 부전대장님! 포위망 돌파에 성공했습니다!","JPN":"副戦隊長殿、報告いたします！\\n包囲網の突破に成功しました！","ENG":"Reporting, Deputy Commander! We've successfully broken through the enemy lines!","TWN":"看啊，副隊長！我們成功突破包圍了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"뒤에 따라붙은 놈들이 있습니다. 인사해 주러 갈까요?","JPN":"後ろにつけてきている連中がいます。\\n挨拶をしに行ってやりましょうか？","ENG":"But we've got a few tailing us. Should we go say hi?","TWN":"有些傢伙還跟在我們後面，要不要跟他們打聲招呼啊？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_TOUCH"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지뢰만 뿌려 둬. 여기서 어물거리다간 금방 다시 둘러싸일 거야.","JPN":"地雷だけばら撒いておいてね。ここでぐずぐずしていたら\\nすぐにまた囲まれちゃうわ。","ENG":"Just lay some mines. They'll surround us again if we linger here too long.","TWN":"設置一些地雷就好，在這裡磨蹭的話，很快又會被包圍的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"당소 함교. 알렉스, 레이더에 고에너지 반응이 포착됐다.","JPN":"こちら艦橋。アレックス、レーダーに高エネルギー反応が観測された。","ENG":"This is the bridge. Alex, we've identified a high energy signature on the radar.","TWN":"這裡是艦橋。雅蕾克絲，雷達偵測到高能量反應。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지상군과 가까운 곳이다. 그쪽에서는 뭔가 보이는 것 없나?","JPN":"座標は地上軍に近い。そちらからは何か見えないか？","ENG":"It's in proximity to the ground troops. Do you see anything down there?","TWN":"就在地面部隊附近，妳那裡有看到什麼嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄? 이 근처에 보이는 거라곤 특별히 없는데......","JPN":"そうね。この辺りからは特に何も見えないけど……","ENG":"I'm not sure. I don't see anything special nearby...","TWN":"是嗎？這附近看起來沒什麼特別的……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":".......이런 썩을.","JPN":"……あらあら。","ENG":"Oh, crud.","TWN":"……該死。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"저건......?! 제 4종 침식체입니다!","JPN":"あれは……！？　第4種侵食体です！","ENG":"It's... It's a Category 4!","TWN":"那是……？！4類侵蝕體！"},"stage":{"bg":"MAINSTREAM_002000","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"교활한 놈! 우리가 가까이 올 때까지 숨어 있었던 건가!","JPN":"姑息な奴め！　隠れて我々を待ち伏せていたのか！","ENG":"That sneaky critter! Was it hiding until we got close?","TWN":"狡猾的渾蛋！它一直躲在這裡，就等我們過來嗎！"},"stage":{"bg":"MAINSTREAM_002000","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"호락호락 당해 주면 안 되지! 대응 포격 준비!","JPN":"みすみすやられはしないわ！　対応砲撃用意！","ENG":"We won't let it take us that easily! Prepare to fire!","TWN":"怎麼可能讓你得逞！準備炮擊！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TANK_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>경고. 동력로가 과부하로 작동 불가 상태입니다.</color>","JPN":"<color=#ffd34c>警告。動力炉が過負荷により作動不能状態です。</color>","ENG":"<color=#ffd34c>Warning. Power line is shut down due to overheating.</color>","TWN":"<color=#ffd34c>警告。動力爐超載，無法運轉。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TANK_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L36_1","type":"dialog","speaker":"TANK_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>냉각 후 재사격까지 1분 40초 소요됩니다.</color>","JPN":"<color=#ffd34c>冷却後、再射撃まで1分40秒を要します。</color>","ENG":"<color=#ffd34c>It will take 1 minute and 40 seconds until the reactor is cool enough to fire again.</color>","TWN":"<color=#ffd34c>冷卻後，離再度射擊需要1分40秒。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TANK_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭐?! 하필 이럴 때......!","JPN":"何ですって！？　よりによってこんな時に……！","ENG":"What? Talk about terrible timing!","TWN":"什麼？！偏偏在這種時候……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"웃......?!","JPN":"うッ……！？","ENG":"Ugh?!","TWN":"呃……？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L44_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"제 4종 침식체, 격파되었습니다!","JPN":"第4種侵食体、撃破されました！","ENG":"Category 4 C.O. destroyed!","TWN":"4類侵蝕體，擊破！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스! 그쪽에서 고출력 CRF 반응이 발생했다!","JPN":"アレックス！　そちらで高出力CRF反応が発生した！","ENG":"Alex! I'm reading high levels of CRF feedback there!","TWN":"雅蕾克絲！那裡有高能CRF反應！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"지원군일 수도 있다! 확인 바란다!","JPN":"援軍かもしれん！　確認を頼む！","ENG":"It might be reinforcements! Please confirm!","TWN":"有可能是援軍！快點確認！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럴 리가...... 전황이 이렇게 불리한데 누가 온다는 거야?","JPN":"そんなことあるわけが……こんな不利な戦況で誰が来られるというの？","ENG":"I doubt it... No one's crazy enough to jump into this mess!","TWN":"怎麼可能……戰況這麼不利，怎麼還會有人來幫我們？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"다들 괜찮습니까?","JPN":"皆さん、ご無事でしたか？","ENG":"Is everyone okay?","TWN":"大家沒事吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"서둘러 온다고 왔는데...... 늦지는 않았는지 모르겠군요.","JPN":"なるべく急いだつもりですが……間に合っていたでしょうか。","ENG":"We rushed here as soon as we could... I hope we're not too late.","TWN":"我是以最快速度趕過來的……不知道有沒有來遲。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};